import logging
from flask import request, abort

log = logging.getLogger(__name__)

@app.route("/login")
def login():
    password = request.form.get("password")
    try:
        raise ValueError("db error")
    except Exception as exc:
        log.error("login failed", extra={"path": request.path, "request_id": request.headers.get("X-Request-ID"), "error": str(exc)})
        # не логируем пароль и не возвращаем детали ошибки пользователю
        abort(500, "Внутренняя ошибка. Попробуйте позже.")

